import { useState } from "react";

const installedPackages = [
  "hyprland",
  "waybar",
  "kitty",
  "rofi",
  "firefox",
  "neovim",
  "git",
  "obsidian",
  "htop",
  "linux-zen",
];

export default function App() {
  const [searchedPkg, setSearchedPkg] = useState("");

  const filteredPackages = installedPackages.filter((pkg) =>
    pkg.includes(searchedPkg),
  );
}
